    const lines = rawData.trim().split('\n').slice(1);

    const dataPeserta = lines.map(line => {
        const columns = line.split('	');
        return {
            noTes: columns[1],
            nama: columns[2],
            nisn: columns[3],
            jk: columns[4],
            cabor: columns[5],
            ttl: columns[6] + ", " + columns[7],
            sekolah: columns[8],
            bb: columns[10] + " kg",
            tb: columns[11] + " cm",
            tensi: columns[12],
            saturasi: columns[13] + "%",
            mata: columns[14],
            fisik: columns[15],
            varises: columns[16]
        };
    });

    function cariData() {
        const input = document.getElementById('searchInput').value.trim().toUpperCase();
        const resultDiv = document.getElementById('result');
        const errorMsg = document.getElementById('error-msg');
        
        // Logika Pencarian: Cek apakah input sama dengan NISN ATAU mengandung bagian dari Nama
        const peserta = dataPeserta.find(d => 
            d.nisn === input || d.nama.includes(input)
        );

        if (peserta && input !== "") {
            errorMsg.style.display = 'none';
            resultDiv.style.display = 'block';
            
            document.getElementById('res-nama').innerText = peserta.nama;
            document.getElementById('res-nisn').innerText = peserta.nisn;
            document.getElementById('res-notes').innerText = peserta.noTes;
            document.getElementById('res-cabor').innerText = peserta.cabor;
            document.getElementById('res-jk').innerText = peserta.jk;
            document.getElementById('res-ttl').innerText = peserta.ttl;
            document.getElementById('res-sekolah').innerText = peserta.sekolah;
            document.getElementById('res-bb').innerText = peserta.bb;
            document.getElementById('res-tb').innerText = peserta.tb;
            document.getElementById('res-saturasi').innerText = peserta.saturasi;
            document.getElementById('res-tensi').innerText = peserta.tensi;
            document.getElementById('res-mata').innerText = peserta.mata;
            document.getElementById('res-fisik').innerText = peserta.fisik;
            document.getElementById('res-varises').innerText = peserta.varises;
            
            // Scroll otomatis ke hasil (untuk mobile)
            resultDiv.scrollIntoView({ behavior: 'smooth' });
        } else {
            resultDiv.style.display = 'none';
            errorMsg.style.display = 'block';
        }
    }

    // Fitur Enter untuk mencari
    document.getElementById("searchInput").addEventListener("keypress", function(event) {
        if (event.key === "Enter") {
            cariData();
        }
    });
